/* PERFECT GLASS THAT NEVER MERGES WITH BACKGROUND */
.glass {
  background: rgba(15, 23, 42, 0.55); /* darker + semi-transparent */
  backdrop-filter: blur(18px) saturate(160%);
  -webkit-backdrop-filter: blur(18px) saturate(160%);
  border: 1px solid rgba(255, 255, 255, 0.06);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.55);
  border-radius: 14px;
}

/* =========================================
   GarudaDrishti - style.css
   Subtle Glass (option B) | radius: 18px | hover: medium | spacing: spacious
   Replace your existing style.css with this file
========================================= */

/* ---------- VARIABLES ---------- */
:root {
  --bg-100: #061019;
  --bg-200: #071523;
  --page-bg: linear-gradient(180deg, var(--bg-100) 0%, var(--bg-200) 100%);
  --card-bg: rgba(18, 28, 40, 0.7);
  --card-contrast: rgba(255, 255, 255, 0.03);
  --muted: #9aa7c7;
  --accent: #00a6ff;
  --accent-2: #1ea7ff;
  --glass-edge: rgba(255, 255, 255, 0.04);

  --radius: 18px;
  --gap: 28px; /* spacious */
  --shadow-mild: 0 10px 30px rgba(3, 8, 18, 0.55);
  --shadow-strong: 0 22px 50px rgba(2, 6, 18, 0.6);
  --glass-blur: 12px;
}

/* ---------- BASE ---------- */
* {
  box-sizing: border-box;
}
html,
body {
  height: 100%;
}
body {
  margin: 0;
  font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto,
    "Helvetica Neue", Arial;
  background: var(--page-bg);
  background-attachment: fixed;
  color: #e6eef8;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  line-height: 1.45;
}

/* ---------- LAYOUT ---------- */
.sidebar {
  width: 260px;
  padding: 30px;
  position: fixed;
  left: 24px;
  top: 24px;
  bottom: 24px;
  border-radius: calc(var(--radius) + 2px);
  display: flex;
  flex-direction: column;
  gap: 18px;
  align-items: flex-start;
  background: linear-gradient(
    180deg,
    rgba(10, 18, 28, 0.48),
    rgba(10, 18, 28, 0.36)
  );
  border: 1px solid rgba(255, 255, 255, 0.02);
  box-shadow: 0 12px 38px rgba(2, 6, 12, 0.55);
  backdrop-filter: blur(8px) saturate(120%);
  -webkit-backdrop-filter: blur(8px) saturate(120%);
  z-index: 40;
}

.main {
  margin-left: 320px;
  padding: 36px;
  max-width: 1300px;
  min-height: 100vh;
}

/* brand */
.brand {
  display: flex;
  gap: 12px;
  align-items: center;
}
.brand__logo {
  width: 56px;
  height: 56px;
  border-radius: 10px;
  object-fit: cover;
}
.brand__title {
  font-weight: 700;
  font-size: 18px;
}
.brand__sub {
  font-size: 12px;
  color: var(--muted);
}

/* nav */
.nav {
  display: flex;
  flex-direction: column;
  gap: 8px;
  width: 100%;
}
.nav__item {
  padding: 10px 12px;
  border-radius: 10px;
  color: var(--muted);
  text-decoration: none;
  display: block;
  width: 100%;
  transition: all 0.22s cubic-bezier(0.2, 0.9, 0.2, 1);
}
.nav__item:hover {
  background: rgba(0, 166, 255, 0.06);
  color: var(--accent);
}
.nav__item--active {
  background: rgba(0, 166, 255, 0.1);
  color: var(--accent);
  box-shadow: inset 0 0 0 1px rgba(0, 0, 0, 0.15);
}

/* headings */
.main__header {
  margin-bottom: 24px;
}
.heading {
  font-size: 34px;
  margin: 0;
}
.lead {
  color: var(--muted);
  margin-top: 8px;
}

/* grid */
.grid {
  display: grid;
  gap: var(--gap);
}
.grid--2cols {
  grid-template-columns: 1.6fr 1fr;
  align-items: start;
}
.grid--4cols {
  grid-template-columns: repeat(4, 1fr);
  align-items: stretch;
  gap: var(--gap);
}
.grid--1col {
  grid-template-columns: 1fr;
}

/* ---------- GLASS CARDS ---------- */
/* subtle glass look (option B) */
.card {
  background: linear-gradient(
    180deg,
    rgba(20, 30, 42, 0.65),
    rgba(10, 18, 30, 0.54)
  );
  border-radius: var(--radius);
  padding: 20px;
  border: 1px solid var(--glass-edge);
  box-shadow: var(--shadow-mild);
  backdrop-filter: blur(var(--glass-blur)) saturate(140%);
  -webkit-backdrop-filter: blur(var(--glass-blur)) saturate(140%);
  transition: transform 0.28s cubic-bezier(0.2, 0.9, 0.2, 1),
    box-shadow 0.28s ease, border-color 0.2s ease;
}

/* card title */
.card__title {
  font-weight: 700;
  margin: 0 0 12px 0;
  color: #e9f6ff;
}
.card__head {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* spacing inside cards slightly larger */
.card p,
.card .muted {
  color: var(--muted);
}

/* make cards visually separated from each other (prevents merger) */
.card + .card {
  margin-top: 6px;
}

/* card hover - medium */
.card:hover {
  transform: translateY(-8px);
  box-shadow: var(--shadow-strong);
  border-color: rgba(255, 255, 255, 0.1);
}

/* slight glass inset at top corners for subtle highlight */
.card::before {
  content: "";
  position: absolute;
  pointer-events: none;
  inset: auto auto calc(100% - 8px) 0;
  height: 8px;
  border-radius: calc(var(--radius) - 14px);
  background: linear-gradient(
    90deg,
    rgba(255, 255, 255, 0.02),
    rgba(255, 255, 255, 0)
  );
}

/* ---------- BUTTONS ---------- */
.btn {
  display: inline-block;
  padding: 8px 14px;
  border-radius: 10px;
  border: 0;
  cursor: pointer;
  font-weight: 700;
}
.btn--primary {
  background: linear-gradient(90deg, var(--accent), var(--accent-2));
  color: #021322;
  box-shadow: 0 6px 18px rgba(0, 166, 255, 0.08);
}
.btn--ghost {
  background: transparent;
  color: var(--muted);
  border: 1px solid rgba(255, 255, 255, 0.03);
}
.btn--muted {
  background: transparent;
  color: var(--muted);
  border: 1px solid rgba(255, 255, 255, 0.04);
}
.btn--danger {
  background: #ff5c5c;
  color: #fff;
}

/* ---------- PREVIEW ---------- */
.preview-wrap {
  position: relative;
  margin-top: 12px;
  height: 420px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 14px;
  overflow: hidden;
}
.preview-canvas {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: contain;
}
.preview-placeholder {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--muted);
  font-size: 14px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.01), transparent);
}

/* ---------- ALERTS / STATS ---------- */
.alerts-grid {
  display: flex;
  gap: 18px;
  margin: 18px 0;
}
.stat {
  flex: 1;
  text-align: center;
  padding: 16px;
  border-radius: 12px;
  background: linear-gradient(
    180deg,
    rgba(255, 255, 255, 0.01),
    rgba(255, 255, 255, 0)
  );
  border: 1px solid rgba(255, 255, 255, 0.02);
}
.stat__count {
  font-weight: 800;
  font-size: 22px;
  color: var(--accent);
}
.stat__label {
  color: var(--muted);
  font-size: 13px;
  margin-top: 6px;
}
.recent-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin-top: 12px;
}
.recent-list .item {
  background: linear-gradient(
    180deg,
    rgba(255, 255, 255, 0.01),
    rgba(255, 255, 255, 0)
  );
  padding: 12px;
  border-radius: 12px;
  color: #dfeeff;
  font-size: 13px;
  border: 1px solid rgba(255, 255, 255, 0.02);
}

/* ---------- FORMS ---------- */
.form {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.input {
  padding: 12px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.03);
  background: transparent;
  color: inherit;
}

/* ---------- SMALL ---------- */
.recent-title {
  margin-top: 10px;
  color: var(--muted);
  font-size: 13px;
}
.muted {
  color: var(--muted);
  font-size: 13px;
}

/* ---------- RESPONSIVE ---------- */
@media (max-width: 1100px) {
  .main {
    margin-left: 300px;
    padding: 22px;
  }
  .grid--4cols {
    grid-template-columns: repeat(2, 1fr);
  }
}
@media (max-width: 900px) {
  .sidebar {
    position: relative;
    left: 12px;
    top: 12px;
    width: 100%;
    display: flex;
    flex-direction: row;
    align-items: center;
    padding: 12px;
    border-radius: 12px;
  }
  .main {
    margin-left: 0;
    padding: 18px;
  }
  .grid--2cols {
    grid-template-columns: 1fr;
  }
  .grid--4cols {
    grid-template-columns: 1fr;
  }
}

/* ---------- ANIMATIONS (alerts & subtle card in) ---------- */
@keyframes slideIn {
  0% {
    transform: translateX(24px);
    opacity: 0;
  }
  100% {
    transform: none;
    opacity: 1;
  }
}
@keyframes pulseGlow {
  0% {
    box-shadow: 0 0 0 rgba(0, 166, 255, 0);
  }
  50% {
    box-shadow: 0 0 12px rgba(0, 166, 255, 0.35);
  }
  100% {
    box-shadow: 0 0 0 rgba(0, 166, 255, 0);
  }
}

.alert-new {
  animation: slideIn 0.36s cubic-bezier(0.2, 0.9, 0.2, 1), pulseGlow 1.2s ease;
}

/* ---------- CHARTS (prevent odd backgrounds merging) ---------- */
canvas {
  background: transparent !important;
  display: block;
  max-width: 100%;
  height: auto !important;
}

/* ---------- HELPERS ---------- */
.small {
  font-size: 13px;
  color: var(--muted);
}
.center {
  text-align: center;
}

/* accessibility focus */
.nav__item:focus,
.btn:focus {
  outline: 3px solid rgba(0, 166, 255, 0.08);
  outline-offset: 2px;
}

/* === Analytics Page Independent Grids === */

/* ---- 4 Cards Overview Row ---- */
.ana-overview {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 22px;
  margin-bottom: 26px;
}

@media (max-width: 1200px) {
  .ana-overview {
    grid-template-columns: repeat(2, 1fr);
  }
}
@media (max-width: 600px) {
  .ana-overview {
    grid-template-columns: 1fr;
  }
}

/* ---- Charts Row (2 columns) ---- */
.ana-charts {
  display: grid;
  grid-template-columns: 1.7fr 1.3fr;
  gap: 22px;
  margin-bottom: 26px;
}

@media (max-width: 980px) {
  .ana-charts {
    grid-template-columns: 1fr;
  }
}

/* ---- Logs Row ---- */
.ana-logs {
  display: grid;
  grid-template-columns: 1fr;
  gap: 22px;
}

/* Fix accent text color */
.brand__title .accent {
  color: var(--accent) !important;
}

/* Analytics overview title size */
#overviewRow h4.small {
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: 0.3px;
}

/* Analytics overview number size */
#overviewRow .stat__count {
  font-size: 2.2rem;
  font-weight: 800;
}

/* Mimic the old "Drishti" look */
.accent {
  color: #4da6ff !important; /* light blue */
  font-weight: 600; /* slightly thinner */
  letter-spacing: 0.6px; /* gives that digital clean look */
  text-shadow: 0 0 4px rgba(77, 166, 255, 0.5),
    /* soft blue glow */ 0 0 8px rgba(77, 166, 255, 0.3);
}
.fa-solid {
  font-size: 19px;
  margin-right: 5px;
}

// js/analytics.js
(() => {
  const API_URL = "http://localhost:8000";

  const fireCountEl = document.getElementById("countFire");
  const smokeCountEl = document.getElementById("countSmoke");
  const fightCountEl = document.getElementById("countFight");
  const logsList = document.getElementById("logsList");

  let timelineChart = null;
  let typeChart = null;

  document.addEventListener("DOMContentLoaded", () => {
    loadAnalytics();
  });

  async function loadAnalytics() {
    try {
      const res = await fetch(`${API_URL}/alerts/all`);
      const data = await res.json();

      updateCounts(data);
      updateLogs(data);
      renderCharts(data);

    } catch (err) {
      console.error("Analytics error:", err);
    }
  }

  /* ---------------------------------------------------
      COUNTS
  ---------------------------------------------------- */
  function updateCounts(arr) {
    const fire = arr.filter(a => /fire/i.test(a.alert_type)).length;
    const smoke = arr.filter(a => /smoke/i.test(a.alert_type)).length;
    const fight = arr.filter(a => /fight/i.test(a.alert_type)).length;

    fireCountEl.textContent = fire;
    smokeCountEl.textContent = smoke;
    fightCountEl.textContent = fight;

    // subtle animation
    animateCount(fireCountEl);
    animateCount(smokeCountEl);
    animateCount(fightCountEl);
  }

  function animateCount(el) {
    el.style.transform = "scale(1.25)";
    el.style.transition = "0.3s";

    setTimeout(() => {
      el.style.transform = "scale(1)";
    }, 300);
  }

  /* ---------------------------------------------------
      RECENT LOGS
  ---------------------------------------------------- */
  function updateLogs(arr) {
    logsList.innerHTML = "";

    arr.slice(0, 10).forEach(log => {
      const item = document.createElement("div");
      item.className = "item";
      item.innerHTML = `
        <b>${log.alert_type}</b>
        <br>
        <span class="muted">${log.description}</span>
        <br>
        <span class="muted">${log.timestamp}</span>
      `;

      item.style.animation = "fadeIn 0.4s ease";
      logsList.appendChild(item);
    });
  }

  /* ---------------------------------------------------
      CHARTS
  ---------------------------------------------------- */
  function renderCharts(arr) {
    const labels = arr.map(a => a.timestamp.split(" ")[1]); // time only
    const fire = arr.map(a => (/fire/i.test(a.alert_type) ? 1 : 0));
    const smoke = arr.map(a => (/smoke/i.test(a.alert_type) ? 1 : 0));
    const fight = arr.map(a => (/fight/i.test(a.alert_type) ? 1 : 0));

    /* ------------------ TIMELINE ------------------ */
    const ctx1 = document.getElementById("timelineChart").getContext("2d");

    if (timelineChart) timelineChart.destroy();

    timelineChart = new Chart(ctx1, {
      type: "line",
      data: {
        labels,
        datasets: [
          {
            label: "Fire",
            data: fire,
            borderColor: "#ff6b6b",
            tension: 0.35
          },
          {
            label: "Smoke",
            data: smoke,
            borderColor: "#cfcfcf",
            tension: 0.35
          },
          {
            label: "Fight",
            data: fight,
            borderColor: "#ffd166",
            tension: 0.35
          }
        ]
      },
      options: {
        plugins: { legend: { labels: { color: "#e8e8e8" } } },
        scales: {
          x: { ticks: { color: "#b5b5b5" } },
          y: { ticks: { color: "#b5b5b5" } }
        }
      }
    });

    /* ------------------ DISTRIBUTION PIE ------------------ */
    const ctx2 = document.getElementById("typeChart").getContext("2d");

    if (typeChart) typeChart.destroy();

    const totalFire = fire.reduce((a, b) => a + b, 0);
    const totalSmoke = smoke.reduce((a, b) => a + b, 0);
    const totalFight = fight.reduce((a, b) => a + b, 0);

    typeChart = new Chart(ctx2, {
      type: "doughnut",
      data: {
        labels: ["Fire", "Smoke", "Fight"],
        datasets: [
          {
            data: [totalFire, totalSmoke, totalFight],
            backgroundColor: ["#ff6b6b", "#cfcfcf", "#ffd166"]
          }
        ]
      },
      options: {
        plugins: { legend: { labels: { color: "#e8e8e8" } } }
      }
    });
  }
})();

// js/app.js
(() => {
  const fileInput = document.getElementById('fileInput');
  const analyzeBtn = document.getElementById('analyzeBtn');
  const canvas = document.getElementById('previewCanvas');
  const placeholder = document.getElementById('previewPlaceholder');
  const statusEl = document.getElementById('status');

  const fireCountEl = document.getElementById('fireCount');
  const smokeCountEl = document.getElementById('smokeCount');
  const fightCountEl = document.getElementById('fightCount');
  const recentAlertsEl = document.getElementById('recentAlerts');
  const clearBtn = document.getElementById('clearAlertsBtn');

  let currentImage = null;
  let ctx = null;

  // track alerts to animate new ones
  let lastAlertIds = new Set();

  // hold detection preview for 10 seconds
  let detectionTimeout = null;

  function setStatus(t) {
    if (!statusEl) return;
    statusEl.textContent = t || '';
  }

  function drawImageAndBoxes(img, detections = []) {
    placeholder.style.display = 'none';
    canvas.style.display = 'block';
    canvas.width = img.width;
    canvas.height = img.height;

    if (!ctx) ctx = canvas.getContext('2d');

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0);

    // draw boxes
    ctx.lineWidth = 3;
    detections.forEach(det => {
      if (!det.bbox) return;

      const [x1, y1, x2, y2] = det.bbox;

      ctx.strokeStyle =
        det.label === 'fire'
          ? '#ff6b6b'
          : det.label === 'smoke'
          ? '#d1d1d1'
          : '#ffd166';

      ctx.strokeRect(x1, y1, x2 - x1, y2 - y1);

      ctx.fillStyle = ctx.strokeStyle;
      ctx.fillRect(x1, Math.max(0, y1 - 22), 70, 22);

      ctx.fillStyle = '#00121a';
      ctx.font = '14px Inter, sans-serif';
      ctx.fillText(det.label, x1 + 6, Math.max(0, y1 - 6));
    });
  }

  // Load image preview
  fileInput &&
    fileInput.addEventListener('change', ev => {
      const f = ev.target.files && ev.target.files[0];
      if (!f) return;

      setStatus('Loaded image — ready');

      const reader = new FileReader();
      reader.onload = e => {
        const img = new Image();
        img.onload = () => {
          currentImage = img;
          drawImageAndBoxes(img, []);
        };
        img.src = e.target.result;
      };
      reader.readAsDataURL(f);
    });

  // Analyze image
  analyzeBtn &&
    analyzeBtn.addEventListener('click', async () => {
      if (!fileInput || !fileInput.files[0])
        return alert('Choose an image first.');

      setStatus('Analyzing image...');
      const fd = new FormData();
      fd.append('file', fileInput.files[0]);

      try {
        const res = await fetch('http://localhost:8000/detection/predict', {
          method: 'POST',
          body: fd
        });

        if (!res.ok) throw new Error('Server error');

        const data = await res.json();

        if (currentImage) {
          drawImageAndBoxes(currentImage, data.detections || []);
        }

        await refreshAlerts();
        setStatus('Detection complete — holding boxes for 10 seconds');

        // --- HOLD THE RESULTS FOR 10 SECONDS ---
        if (detectionTimeout) clearTimeout(detectionTimeout);

        detectionTimeout = setTimeout(() => {
          if (currentImage) {
            drawImageAndBoxes(currentImage, []); // remove boxes, keep image
            setStatus('Preview reset — ready for next upload');
          }
        }, 10000);
      } catch (err) {
        console.error(err);
        setStatus('Analysis failed — check backend');
        alert('Detection failed. See console.');
      }
    });

  // Fetch alerts + animate new ones
  async function refreshAlerts() {
    try {
      const res = await fetch('http://localhost:8000/alerts/all');
      if (!res.ok) throw new Error('Failed to fetch alerts');

      const arr = await res.json();

      // counts
      const fire = arr.filter(a => /fire/i.test(a.alert_type)).length;
      const smoke = arr.filter(a => /smoke/i.test(a.alert_type)).length;
      const fight = arr.filter(a => /fight/i.test(a.alert_type)).length;

      fireCountEl && (fireCountEl.textContent = fire);
      smokeCountEl && (smokeCountEl.textContent = smoke);
      fightCountEl && (fightCountEl.textContent = fight);

      // recent alerts with animation
      if (recentAlertsEl) {
        recentAlertsEl.innerHTML = '';

        arr.slice(0, 6).forEach(a => {
          const d = document.createElement('div');
          d.className = 'item';
          d.textContent = `${a.alert_type} — ${a.description || ''} (${a.timestamp || ''})`;

          // highlight new alerts
          if (!lastAlertIds.has(a.id)) {
            d.classList.add('alert-new');
          }

          recentAlertsEl.appendChild(d);
          lastAlertIds.add(a.id);
        });
      }
    } catch (e) {
      console.warn('refreshAlerts error', e);
    }
  }

  // Clear alerts
  clearBtn &&
    clearBtn.addEventListener('click', async () => {
      if (!confirm('Clear all alerts?')) return;

      try {
        await fetch('http://localhost:8000/alerts/clear', {
          method: 'DELETE'
        });

        lastAlertIds = new Set(); // reset animations
        await refreshAlerts();
      } catch (e) {
        console.warn('clear failed', e);
      }
    });

  // Initial
  document.addEventListener('DOMContentLoaded', () => {
    if (canvas) canvas.style.display = 'none';
    refreshAlerts();
  });
})();

