/* ---------- VARIABLES ---------- */
:root {
  --bg-100: #061019;
  --bg-200: #071523;
  --page-bg: linear-gradient(180deg, var(--bg-100) 0%, var(--bg-200) 100%);
  --card-bg: rgba(18, 28, 40, 0.7);
  --card-contrast: rgba(255, 255, 255, 0.03);
  --muted: #9aa7c7;
  --accent: #00a6ff;
  --accent-2: #1ea7ff;
  --glass-edge: rgba(255, 255, 255, 0.04);

  --radius: 18px;
  --gap: 28px; /* spacious */
  --shadow-mild: 0 10px 30px rgba(3, 8, 18, 0.55);
  --shadow-strong: 0 22px 50px rgba(2, 6, 18, 0.6);
  --glass-blur: 12px;
}

/* ---------- BASE ---------- */
* {
  box-sizing: border-box;
}
html,
body {
  height: 100%;
}
body {
  margin: 0;
  font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto,
    "Helvetica Neue", Arial;
  background: var(--page-bg);
  background-attachment: fixed;
  color: #e6eef8;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  line-height: 1.45;
}

/* ---------- LAYOUT ---------- */
.sidebar {
  width: 260px;
  padding: 30px;
  position: fixed;
  left: 24px;
  top: 24px;
  bottom: 24px;
  border-radius: calc(var(--radius) + 2px);
  display: flex;
  flex-direction: column;
  gap: 18px;
  align-items: flex-start;
  background: linear-gradient(
    180deg,
    rgba(10, 18, 28, 0.48),
    rgba(10, 18, 28, 0.36)
  );
  border: 1px solid rgba(255, 255, 255, 0.02);
  box-shadow: 0 12px 38px rgba(2, 6, 12, 0.55);
  backdrop-filter: blur(8px) saturate(120%);
  -webkit-backdrop-filter: blur(8px) saturate(120%);
  z-index: 40;
}

.main {
  margin-left: 320px;
  padding: 36px;
  max-width: 1300px;
  min-height: 100vh;
}

/* brand */
.brand {
  display: flex;
  gap: 12px;
  align-items: center;
}
.brand__logo {
  width: 56px;
  height: 56px;
  border-radius: 10px;
  object-fit: cover;
}
.brand__title {
  font-weight: 700;
  font-size: 18px;
}
.brand__sub {
  font-size: 12px;
  color: var(--muted);
}

/* nav */
.nav {
  display: flex;
  flex-direction: column;
  gap: 8px;
  width: 100%;
}
.nav__item {
  padding: 10px 12px;
  border-radius: 10px;
  color: var(--muted);
  text-decoration: none;
  display: block;
  width: 100%;
  transition: all 0.22s cubic-bezier(0.2, 0.9, 0.2, 1);
