  margin-bottom: 24px;
}
.heading {
  font-size: 34px;
  margin: 0;
}
.lead {
  color: var(--muted);
  margin-top: 8px;
}

/* grid */
.grid {
  display: grid;
  gap: var(--gap);
}
.grid--2cols {
  grid-template-columns: 1.6fr 1fr;
  align-items: start;
}
.grid--4cols {
  grid-template-columns: repeat(4, 1fr);
  align-items: stretch;
  gap: var(--gap);
}
.grid--1col {
  grid-template-columns: 1fr;
}

/* ---------- GLASS CARDS ---------- */
/* subtle glass look (option B) */
.card {
  background: linear-gradient(
    180deg,
    rgba(20, 30, 42, 0.65),
    rgba(10, 18, 30, 0.54)
  );
  border-radius: var(--radius);
  padding: 20px;
  border: 1px solid var(--glass-edge);
  box-shadow: var(--shadow-mild);
  backdrop-filter: blur(var(--glass-blur)) saturate(140%);
  -webkit-backdrop-filter: blur(var(--glass-blur)) saturate(140%);
  transition: transform 0.28s cubic-bezier(0.2, 0.9, 0.2, 1),
    box-shadow 0.28s ease, border-color 0.2s ease;
}

/* card title */
.card__title {
  font-weight: 700;
  margin: 0 0 12px 0;
  color: #e9f6ff;
}
.card__head {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* spacing inside cards slightly larger */
.card p,
.card .muted {
  color: var(--muted);
}

/* make cards visually separated from each other (prevents merger) */
.card + .card {
  margin-top: 6px;
}

/* card hover - medium */
.card:hover {
  transform: translateY(-8px);
  box-shadow: var(--shadow-strong);
  border-color: rgba(255, 255, 255, 0.1);
}

/* slight glass inset at top corners for subtle highlight */
.card::before {
  content: "";
  position: absolute;
  pointer-events: none;
  inset: auto auto calc(100% - 8px) 0;
  height: 8px;
  border-radius: calc(var(--radius) - 14px);
  background: linear-gradient(
    90deg,
    rgba(255, 255, 255, 0.02),
    rgba(255, 255, 255, 0)
  );
}

/* ---------- BUTTONS ---------- */
.btn {
  display: inline-block;
  padding: 8px 14px;
  border-radius: 10px;
  border: 0;
  cursor: pointer;
  font-weight: 700;
}
.btn--primary {
  background: linear-gradient(90deg, var(--accent), var(--accent-2));
  color: #021322;
  box-shadow: 0 6px 18px rgba(0, 166, 255, 0.08);
}
.btn--ghost {
  background: transparent;
  color: var(--muted);
  border: 1px solid rgba(255, 255, 255, 0.03);
}
.btn--muted {
  background: transparent;
  color: var(--muted);
  border: 1px solid rgba(255, 255, 255, 0.04);
}
.btn--danger {
  background: #ff5c5c;
  color: #fff;
}

/* ---------- PREVIEW ---------- */
.preview-wrap {
  position: relative;
  margin-top: 12px;
  height: 420px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 14px;
  overflow: hidden;
}
.preview-canvas {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: contain;
}
.preview-placeholder {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--muted);
  font-size: 14px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.01), transparent);
}

/* ---------- ALERTS / STATS ---------- */
.alerts-grid {
  display: flex;
  gap: 18px;
  margin: 18px 0;
}
.stat {
  flex: 1;
  text-align: center;
