import re
import bcrypt
from flask import Blueprint, request, jsonify
from flask_jwt_extended import create_access_token, jwt_required, get_jwt_identity, get_jwt

from database import execute
from extensions import limiter, csrf

auth_bp = Blueprint('auth', __name__)

# Allow usernames or email-like identifiers (allows @ +) to support common login patterns
USERNAME_RE = re.compile(r'^[a-zA-Z0-9_.@+-]{4,64}$')


def _get_user(username):
    row = execute(
        'SELECT id, username, password, role, tenant_id, full_name, bio, avatar_url, google_url, facebook_url, linkedin_url, github_url '
        'FROM users WHERE username = %s',
        (username,),
        fetchone=True,
    )
    return dict(row) if row else None


def _serialize_profile(user):
    return {
        'username': user['username'],
        'role': user['role'],
        'tenant_id': user.get('tenant_id', 'default'),
        'full_name': user.get('full_name') or '',
        'bio': user.get('bio') or '',
        'avatar_url': user.get('avatar_url') or '',
        'social_links': {
            'google': user.get('google_url') or '',
            'facebook': user.get('facebook_url') or '',
            'linkedin': user.get('linkedin_url') or '',
            'github': user.get('github_url') or '',
        },
    }


def _hash_password(password: str) -> str:
    return bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')


def _verify_password(password: str, hashed: str) -> bool:
    try:
        return bcrypt.checkpw(password.encode('utf-8'), hashed.encode('utf-8'))
    except Exception:
        return False


def _require_admin(fn):
    from functools import wraps

    @wraps(fn)
    @jwt_required()
    def wrapper(*args, **kwargs):
        claims = get_jwt()
        if claims.get('role') != 'admin':
            return jsonify({'error': 'Admin access required'}), 403
        return fn(*args, **kwargs)

    return wrapper


@auth_bp.route('/register', methods=['POST'])
@csrf.exempt
def register():
    data = request.get_json() or {}
    username = (data.get('username') or '').strip()
    password = data.get('password') or ''
    full_name = (data.get('full_name') or '').strip()

    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    if not USERNAME_RE.match(username):
        return jsonify({'error': 'Username must be 4-64 characters and can include letters, numbers, . _ @ + -'}), 400
    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    if _get_user(username):
        return jsonify({'error': 'User already exists'}), 400

    tenant_id = (data.get('tenant_id') or 'default').strip() or 'default'
    hashed = _hash_password(password)
    execute(
        'INSERT INTO users (username, password, role, tenant_id, full_name) VALUES (%s, %s, %s, %s, %s)',
        (username, hashed, 'user', tenant_id, full_name),
        commit=True
    )

    return jsonify({'message': 'User registered'})


@auth_bp.route('/login', methods=['POST'])
@limiter.limit('5 per minute')
@csrf.exempt
def login():
    data = request.get_json() or {}
    username = (data.get('username') or '').strip()
    password = data.get('password') or ''

    user = _get_user(username)
    if not user or not _verify_password(password, user['password']):
        return jsonify({'error': 'Invalid credentials'}), 401

    access_token = create_access_token(
        identity=username,
        additional_claims={
            'role': user.get('role', 'user'),
            'tenant_id': user.get('tenant_id', 'default'),
        },
    )
    return jsonify({'token': access_token})


@auth_bp.route('/me', methods=['GET'])
@jwt_required()
def me():
    username = get_jwt_identity()
    user = _get_user(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    return jsonify(_serialize_profile(user))


@auth_bp.route('/profile', methods=['PUT'])
@jwt_required()
@csrf.exempt
def update_profile():
    username = get_jwt_identity()
    user = _get_user(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    data = request.get_json() or {}
    social_links = data.get('social_links') or {}
    full_name = (data.get('full_name') or '').strip()
    bio = (data.get('bio') or '').strip()
    avatar_url = (data.get('avatar_url') or '').strip()

    execute(
        'UPDATE users SET full_name = %s, bio = %s, avatar_url = %s, google_url = %s, facebook_url = %s, linkedin_url = %s, github_url = %s WHERE username = %s',
        (
            full_name,
            bio,
            avatar_url,
            (social_links.get('google') or '').strip(),
            (social_links.get('facebook') or '').strip(),
            (social_links.get('linkedin') or '').strip(),
            (social_links.get('github') or '').strip(),
            username,
        ),
        commit=True,
    )

    updated_user = _get_user(username)
    return jsonify({'message': 'Profile updated', 'profile': _serialize_profile(updated_user)})


@auth_bp.route('/admin/users', methods=['GET'])
@_require_admin
def list_users():
    rows = execute('SELECT id, username, role, tenant_id, created_at FROM users ORDER BY created_at DESC', fetchall=True)
    users = [dict(r) for r in rows] if rows else []
    return jsonify({'users': users})

import os
from datetime import datetime

import psycopg2
from psycopg2.extras import RealDictCursor

# Paths
SCHEMA_PATH = os.path.join(os.path.dirname(__file__), '..', 'database', 'schema.sql')
SQLITE_DB_PATH = os.path.join(os.path.dirname(__file__), '..', 'app.db')
PROFILE_COLUMNS = {
    'full_name': 'TEXT',
    'bio': 'TEXT',
    'avatar_url': 'TEXT',
    'google_url': 'TEXT',
    'facebook_url': 'TEXT',
    'linkedin_url': 'TEXT',
    'github_url': 'TEXT',
}


def get_conn():
    """Return a DB connection.

    Uses PostgreSQL when DATABASE_URL is set, otherwise uses SQLite.
    """
    db_url = os.getenv('DATABASE_URL')
    if db_url:
        return psycopg2.connect(db_url, cursor_factory=RealDictCursor)

    import sqlite3
    conn = sqlite3.connect(SQLITE_DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn


def _is_sqlite_connection(conn) -> bool:
    return 'sqlite3' in type(conn).__module__


def _sqlite_schema_needs_reset(conn) -> bool:
    """Detect legacy SQLite tables created from PostgreSQL syntax."""
    try:
        users_table = conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='users'").fetchone()
        if not users_table:
            return False

        columns = conn.execute('PRAGMA table_info(users)').fetchall()
        id_column = next((col for col in columns if col[1] == 'id'), None)
        if not id_column:
            return True

        # Legacy DBs created `SERIAL PRIMARY KEY`, which breaks inserts in SQLite.
        return str(id_column[2]).upper() != 'INTEGER'
    except Exception:
        return True


def _adapt_query(query: str, conn):
    """Adjust query placeholders based on DB driver.

    psycopg2 uses %s, sqlite3 uses ?.
    """

    if 'sqlite3' in type(conn).__module__:
        return query.replace('%s', '?')
    return query


def execute(query, params=None, fetchone=False, fetchall=False, commit=False, return_lastrowid=False):
    """Execute a SQL query in a safe, parameterized way.

    Args:
        query: SQL query string with %s placeholders.
        params: Tuple of parameters.
        fetchone: Return a single row.
        fetchall: Return all rows.
        commit: Commit transaction.
        return_lastrowid: Return the last inserted row ID when committing.
    """
    params = params or ()
    conn = get_conn()
    cur = conn.cursor()

    try:
        q = _adapt_query(query, conn)
        cur.execute(q, params)
        lastrowid = None
        if commit:
            conn.commit()
            if return_lastrowid:
                # sqlite exposes lastrowid on cursor
                if hasattr(cur, 'lastrowid') and cur.lastrowid:
                    lastrowid = cur.lastrowid
                # psycopg2 can return via RETURNING clause if used by the caller
        if fetchone:
            return cur.fetchone()
        if fetchall:
            return cur.fetchall()
        if return_lastrowid:
            return lastrowid
    finally:
        cur.close()
        conn.close()


def init_db():
    """Initialize the database schema from schema.sql."""
    conn = get_conn()
    cur = conn.cursor()

    with open(SCHEMA_PATH, 'r', encoding='utf-8') as f:
        sql = f.read()

    if _is_sqlite_connection(conn) and _sqlite_schema_needs_reset(conn):
        cur.close()
        conn.close()

        if os.path.exists(SQLITE_DB_PATH):
            backup_path = f"{SQLITE_DB_PATH}.bak.{datetime.now().strftime('%Y%m%d%H%M%S')}"
            os.replace(SQLITE_DB_PATH, backup_path)

        conn = get_conn()
        cur = conn.cursor()

    if _is_sqlite_connection(conn):
        sqlite_sql = (
            sql.replace('SERIAL PRIMARY KEY', 'INTEGER PRIMARY KEY AUTOINCREMENT')
            .replace('JSONB', 'TEXT')
            .replace('BOOLEAN DEFAULT FALSE', 'INTEGER DEFAULT 0')
        )
        conn.executescript(sqlite_sql)
    else:
        # psycopg2 cannot execute multiple statements at once
        statements = [s.strip() for s in sql.split(';') if s.strip()]
        for stmt in statements:
            cur.execute(stmt)

    conn.commit()
    _ensure_user_profile_columns(conn)
    cur.close()
    conn.close()


def _ensure_user_profile_columns(conn):
    """Add profile-related columns when running against older local databases."""
    cur = conn.cursor()
    try:
        if _is_sqlite_connection(conn):
            existing = {row[1] for row in conn.execute('PRAGMA table_info(users)').fetchall()}
            for column, definition in PROFILE_COLUMNS.items():
                if column not in existing:
                    conn.execute(f'ALTER TABLE users ADD COLUMN {column} {definition}')
        else:
            cur.execute(
                """
                SELECT column_name
                FROM information_schema.columns
                WHERE table_name = 'users'
                """
            )
            existing = {row['column_name'] if isinstance(row, dict) else row[0] for row in cur.fetchall()}
            for column in PROFILE_COLUMNS:
                if column not in existing:
                    cur.execute(f'ALTER TABLE users ADD COLUMN {column} TEXT')
        conn.commit()
    finally:
        cur.close()

