"""Simple in-process pub/sub helpers for real-time dashboard updates."""

from queue import Queue
from threading import Lock

_listeners = []
_lock = Lock()


def subscribe():
    queue = Queue()
    with _lock:
      _listeners.append(queue)
    return queue


def unsubscribe(queue):
    with _lock:
        if queue in _listeners:
            _listeners.remove(queue)


def publish_dashboard_update(payload=None):
    message = payload or {'type': 'dashboard-updated'}
    with _lock:
        listeners = list(_listeners)

    for queue in listeners:
        queue.put(message)

import re
import socket
import ssl

import requests
from bs4 import BeautifulSoup
from urllib3.exceptions import InsecureRequestWarning


requests.packages.urllib3.disable_warnings(category=InsecureRequestWarning)

DEFAULT_HEADERS = {
    'User-Agent': 'Mozilla/5.0 (compatible; CyberShieldLab/1.0; +http://127.0.0.1)',
    'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
}


class VulnerabilityReport:
    def __init__(self, target_url: str):
        self.target_url = target_url
        self.vulns = []

    def add(self, name, level, description, fix, evidence=None):
        self.vulns.append({
            'name': name,
            'level': level,
            'description': description,
            'fix': fix,
            'evidence': evidence,
        })

    def summary(self):
        levels = {'Low': 0, 'Medium': 0, 'High': 0, 'Critical': 0}
        for vuln in self.vulns:
            levels[vuln['level']] += 1
        return {
            'target': self.target_url,
            'counts': levels,
            'details': self.vulns,
        }


def _normalize_url(url: str) -> str:
    normalized = (url or '').strip()
    if not normalized:
        return normalized
    if not normalized.startswith(('http://', 'https://')):
        normalized = f'https://{normalized}'
    return normalized


def _build_session():
    session = requests.Session()
    session.headers.update(DEFAULT_HEADERS)
    return session


def _fetch(session, url, **kwargs):
    """Wrapper around requests.get with timeout and safe exception handling."""
    try:
        response = session.get(url, timeout=12, allow_redirects=True, verify=True, **kwargs)
        response.raise_for_status()
