$RefreshReg$(_c, "MalwareLab");","map":{"version":3,"names":["React","useState","useEffect","useNavigate","axios","jsxDEV","_jsxDEV","Fragment","_Fragment","MalwareLab","_s","navigate","file","setFile","result","setResult","error","setError","history","setHistory","loading","setLoading","authTick","setAuthTick","authToken","localStorage","getItem","fetchHistory","onStorage","event","key","t","window","addEventListener","removeEventListener","res","get","data","err","console","upload","formData","FormData","append","post","headers","_err$response","_err$response$data","_err$response2","msg","response","JSON","stringify","message","isLoggedIn","Boolean","className","children","fileName","_jsxFileName","lineNumber","columnNumber","onClick","location","reload","type","onChange","e","target","files","accept","style","minWidth","name","disabled","role","length","map","scan","filename","status","Date","scanned_at","toLocaleString","href","id","file_name","file_type","file_size","entropy","sha256","md5","sha1","indicators","indicator","idx","scan_id","_c","$RefreshReg$"],"sources":["C:/Users/suman/Music/projects-csecurity/tools-scanners-website/frontend/src/MalwareLab.js"],"sourcesContent":["import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function MalwareLab() {
  const navigate = useNavigate();
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [authTick, setAuthTick] = useState(0);

  const authToken = localStorage.getItem('jwt_token');

  useEffect(() => {
    if (authToken) {
      fetchHistory();
    }
  }, [authToken, authTick]);

  useEffect(() => {
    const onStorage = (event) => {
      if (event.key === 'jwt_token') {
        setAuthTick((t) => t + 1);
      }
    };

    window.addEventListener('storage', onStorage);
    return () => window.removeEventListener('storage', onStorage);
  }, []);

  const fetchHistory = async () => {
    try {
      const res = await axios.get('/api/malware/history');
      setHistory(res.data.history || []);
    } catch (err) {
      console.error('Failed to fetch history:', err);
    }
  };

  const upload = async () => {
    setError(null);
    setResult(null);

    if (!authToken) {
      setError('You must be logged in to run a scan. Please go to the Secure Web App and login.');
      return;
    }

    if (!file) {
      setError('Please select a file to scan.');
      return;
    }

    setLoading(true);

    const formData = new FormData();
    formData.append('file', file);

    try {
      const res = await axios.post('/api/malware/scan', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      setResult(res.data);
      fetchHistory(); // refresh history
    } catch (err) {
      const msg =
        err.response?.data?.error ||
        (err.response?.data && JSON.stringify(err.response.data)) ||
        err.message ||
        'Scan failed.';
      setError(`Scan failed: ${msg}`);
    } finally {
      setLoading(false);
    }
  };

  const isLoggedIn = Boolean(authToken);

  return (
    <div className="container-fluid">
      <div className="row">
        <div className="col-12">
          <div className="d-flex justify-content-between align-items-center mb-3">
            <div>
              <h2 className="mb-1">Malware Analysis Lab</h2>
              <small className="text-muted">Upload a suspicious file and run analysis using the built-in scanner.</small>
            </div>
            <div className="d-flex align-items-center gap-2">
              <span className={`badge ${isLoggedIn ? 'bg-success' : 'bg-warning'}`}>
                {isLoggedIn ? 'Logged in' : 'Not logged in'}
              </span>
              <button className="btn btn-sm btn-outline-light" onClick={() => window.location.reload()}>
                Reset
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="row">
        <div className="col-lg-6 col-md-12 mb-4">
          <div className="card bg-dark text-white h-100">
            <div className="card-body">
              <h5 className="card-title">Upload & Scan</h5>
              <div className="mb-3">
                <label className="form-label">Upload suspicious file</label>
                <div className="input-group input-group-lg">
                  <input
                    className="form-control bg-secondary text-light"
                    type="file"
                    onChange={(e) => setFile(e.target.files[0])}
                    accept=".exe,.dll,.pdf,.doc,.docx,.xls,.xlsx,.zip,.rar"
                  />
                  <span className="input-group-text bg-dark text-white" style={{ minWidth: '220px' }}>
                    {file ? file.name : 'No file chosen'}
                  </span>
                </div>
              </div>
              <button className="btn btn-primary w-100" onClick={upload} disabled={loading || !authToken}>
                {loading ? (
                  <>
                    <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true" />
                    Scanning...
                  </>
                ) : (
                  'Run Analysis'
                )}
              </button>

              {error && <div className="alert alert-danger mt-3">{error}</div>}

              {!authToken && (
                <div className="alert alert-warning mt-3">
                  <strong>Log in required:</strong> use the Secure Web App module to authenticate before scanning.
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="col-lg-6 col-md-12 mb-4">
          <div className="card bg-dark text-white h-100">
            <div className="card-body">
              <h5 className="card-title">Scan History</h5>
              {history.length === 0 ? (
                <p className="text-muted">No scans yet.</p>
              ) : (
                <div className="table-responsive">
                  <table className="table table-dark table-striped">
                    <thead>
                      <tr>
                        <th>File</th>
                        <th>Status</th>
                        <th>Scanned At</th>
                        <th>Action</th>
                      </tr>
                    </thead>
                    <tbody>
                      {history.map((scan) => (
                        <tr key={scan.id}>
                          <td>{scan.filename}</td>
                          <td>
                            <span
                              className={
                                scan.status === 'MALICIOUS'
                                  ? 'text-danger'
                                  : scan.status === 'SUSPICIOUS'
                                  ? 'text-warning'
                                  : 'text-success'
                              }
                            >
                              {scan.status}
                            </span>
                          </td>
                          <td>{new Date(scan.scanned_at).toLocaleString()}</td>
                          <td>
                            <a
                              href={`/api/malware/report/${scan.id}?download=1`}
                              className="btn btn-outline-light btn-sm"
                            >
                              Download
                            </a>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {result && (
        <div className="row">
          <div className="col-12">
            <div className="card bg-dark text-white">
              <div className="card-body">
                <h4 className="card-title">Scan Result</h4>
                <div className="row">
                  <div className="col-md-6">
                    <p className="mb-1">
                      <strong>Status:</strong>{' '}
                      <span
                        className={
                          result.status === 'MALICIOUS'
                            ? 'text-danger'
                            : result.status === 'SUSPICIOUS'
                            ? 'text-warning'
                            : 'text-success'
                        }
                      >
                        {result.status}
                      </span>
                    </p>
                    <p className="mb-1">
                      <strong>File:</strong> {result.file_name}
                    </p>
                    <p className="mb-1">
                      <strong>Type:</strong> {result.file_type || 'Unknown'}
                    </p>
                    <p className="mb-1">
                      <strong>Size:</strong> {result.file_size} bytes
                    </p>
                    <p className="mb-1">
                      <strong>Entropy:</strong> {result.entropy}
                    </p>
                  </div>
                  <div className="col-md-6">
                    <p className="mb-1">
                      <strong>SHA256:</strong> <code className="text-break">{result.sha256}</code>
                    </p>
                    <p className="mb-1">
                      <strong>MD5:</strong> <code>{result.md5}</code>
                    </p>
                    <p className="mb-1">
                      <strong>SHA1:</strong> <code>{result.sha1}</code>
                    </p>
                  </div>
                </div>

                {result.indicators && result.indicators.length > 0 && (
                  <div className="mt-3">
                    <h6>Suspicious Indicators</h6>
                    <ul>
                      {result.indicators.map((indicator, idx) => (
                        <li key={idx}>{indicator}</li>
                      ))}
                    </ul>
                  </div>
                )}

                {result.scan_id && (
                  <div className="mt-3">
                    <a
                      href={`/api/malware/report/${result.scan_id}?download=1`}
                      className="btn btn-outline-light btn-sm"
                    >
                      Download Full Report
                    </a>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
