import { useNavigate } from 'react-router-dom';
import axios from './api';
import { useAuth } from './AuthContext';

const EMPTY_PROFILE = {
  username: '',
  role: '',
  tenant_id: 'default',
  full_name: '',
  bio: '',
  avatar_url: '',
  social_links: {
    google: '',
    facebook: '',
    linkedin: '',
    github: '',
  },
};

const SOCIAL_SHORTCUTS = [
  { key: 'google', label: 'Google', href: 'https://www.google.com/' },
  { key: 'facebook', label: 'Facebook', href: 'https://www.facebook.com/' },
  { key: 'linkedin', label: 'LinkedIn', href: 'https://www.linkedin.com/' },
  { key: 'github', label: 'GitHub', href: 'https://github.com/' },
];

function Auth() {
  const navigate = useNavigate();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [tenant, setTenant] = useState('default');
  const [fullName, setFullName] = useState('');
  const [message, setMessage] = useState('');
  const [profile, setProfile] = useState(EMPTY_PROFILE);
  const [savingProfile, setSavingProfile] = useState(false);
  const { token, setToken } = useAuth();

  useEffect(() => {
    if (token) {
      fetchProfile();
    } else {
      setProfile(EMPTY_PROFILE);
    }
  }, [token]);

  const fetchProfile = async () => {
    try {
      const res = await axios.get('/api/auth/me');
      setProfile({ ...EMPTY_PROFILE, ...res.data, social_links: { ...EMPTY_PROFILE.social_links, ...(res.data.social_links || {}) } });
      setTenant(res.data.tenant_id || 'default');
      if (res.data.full_name) {
        setFullName(res.data.full_name);
      }
    } catch (err) {
      setMessage(err.response?.data?.error || 'Failed to fetch profile.');
    }
  };

  const register = async () => {
    setMessage('');
    try {
      const res = await axios.post('/api/auth/register', {
        username,
        password,
        tenant_id: tenant,
        full_name: fullName,
      });
      setMessage(`${res.data.message}. You can log in now.`);
    } catch (err) {
      setMessage(err.response?.data?.error || 'Registration failed.');
    }
  };

  const login = async () => {
    setMessage('');
    try {
      const res = await axios.post('/api/auth/login', {
        username,
        password,
        tenant_id: tenant,
      });
      setToken(res.data.token);
      setMessage('Login successful. Redirecting...');
      setTimeout(() => navigate('/malware'), 700);
    } catch (err) {
      setMessage(err.response?.data?.error || 'Login failed. Register first or check your password.');
    }
  };

  const logout = () => {
    setToken(null);
    setProfile(EMPTY_PROFILE);
    setMessage('Logged out.');
  };

  const updateSocialLink = (key, value) => {
    setProfile((current) => ({
      ...current,
      social_links: {
        ...current.social_links,
        [key]: value,
      },
    }));
  };

  const handleAvatarChange = (event) => {
    const file = event.target.files?.[0];
    if (!file) {
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      setProfile((current) => ({
        ...current,
        avatar_url: reader.result,
      }));
    };
    reader.readAsDataURL(file);
  };

  const saveProfile = async () => {
    setSavingProfile(true);
    setMessage('');
    try {
      const res = await axios.put('/api/auth/profile', {
        full_name: profile.full_name,
        bio: profile.bio,
        avatar_url: profile.avatar_url,
        social_links: profile.social_links,
      });
      setProfile({ ...EMPTY_PROFILE, ...res.data.profile, social_links: { ...EMPTY_PROFILE.social_links, ...(res.data.profile.social_links || {}) } });
      setMessage(res.data.message);
    } catch (err) {
      setMessage(err.response?.data?.error || 'Failed to save profile.');
    } finally {
      setSavingProfile(false);
    }
  };

  const initials = (profile.full_name || profile.username || 'CS')
    .split(' ')
    .filter(Boolean)
    .slice(0, 2)
    .map((item) => item[0]?.toUpperCase())
    .join('');

  return (
    <div className="page-shell">
      <section className="hero-panel">
        <div>
          <span className="eyebrow">Identity</span>
          <h1>Secure App Access</h1>
          <p>Sign in, manage your profile, add your photo, and keep quick links to your favorite platforms in one place.</p>
        </div>
      </section>

      <section className="content-grid auth-layout">
        <div className="glass-card">
          <h5 className="card-title">Authentication</h5>
          <div className="mb-2">
            <label className="form-label">Full name</label>
            <input className="form-control" value={fullName} onChange={(e) => setFullName(e.target.value)} placeholder="Your name" />
          </div>
          <div className="mb-2">
            <label className="form-label">Username or email</label>
            <input className="form-control" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="username@gmail.com" />
          </div>
          <div className="mb-2">
            <label className="form-label">Tenant ID</label>
            <input className="form-control" value={tenant} onChange={(e) => setTenant(e.target.value)} placeholder="tenant id (e.g. default)" />
            <small className="form-text">Used to group users and scan history.</small>
          </div>
          <div className="mb-3">
            <label className="form-label">Password</label>
            <input
              type="password"
              className="form-control"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="password"
            />
          </div>
          <div className="d-flex flex-wrap gap-2">
            <button className="btn btn-outline-secondary" onClick={register}>
              Register
            </button>
            <button className="btn btn-primary" onClick={login}>
              Login
            </button>
            <button className="btn btn-outline-light" onClick={logout}>
              Logout
            </button>
          </div>
          {message && <div className="alert alert-info mt-3">{message}</div>}

          <div className="stack-list mt-4">
            <div className="stack-item">
              <strong>Direct platforms</strong>
              <p>Use these shortcuts to open Google, Facebook, LinkedIn, or GitHub directly.</p>
              <div className="d-flex flex-wrap gap-2 mt-2">
                {SOCIAL_SHORTCUTS.map((item) => (
                  <a key={item.key} className="btn btn-outline-light btn-sm" href={item.href} target="_blank" rel="noreferrer">
                    {item.label}
                  </a>
                ))}
              </div>
            </div>
          </div>
        </div>

        <div className="glass-card">
          <h5 className="card-title">Profile</h5>
          {token ? (
            <>
              <div className="profile-header">
                <div className="profile-avatar">
                  {profile.avatar_url ? <img src={profile.avatar_url} alt="Profile" className="profile-avatar-image" /> : <span>{initials || 'CS'}</span>}
                </div>
                <div>
                  <strong className="profile-name">{profile.full_name || profile.username}</strong>
                  <p className="mb-1">{profile.username}</p>
                  <small>{profile.role} in tenant {profile.tenant_id}</small>
                </div>
              </div>

              <div className="mb-3">
                <label className="form-label">Profile photo</label>
                <input className="form-control" type="file" accept="image/*" onChange={handleAvatarChange} />
              </div>

              <div className="mb-3">
                <label className="form-label">Full name</label>
                <input
                  className="form-control"
                  value={profile.full_name}
                  onChange={(e) => setProfile((current) => ({ ...current, full_name: e.target.value }))}
                  placeholder="Your display name"
                />
              </div>

              <div className="mb-3">
                <label className="form-label">Bio</label>
                <textarea
                  className="form-control"
                  value={profile.bio}
                  onChange={(e) => setProfile((current) => ({ ...current, bio: e.target.value }))}
                  placeholder="Tell people a bit about yourself"
                  rows={4}
                />
              </div>

              <div className="stack-list">
                {SOCIAL_SHORTCUTS.map((item) => (
                  <div className="stack-item" key={item.key}>
                    <strong>{item.label} profile</strong>
                    <input
                      className="form-control mt-2"
                      value={profile.social_links[item.key] || ''}
                      onChange={(e) => updateSocialLink(item.key, e.target.value)}
                      placeholder={`Paste your ${item.label} profile URL`}
                    />
                    <div className="d-flex flex-wrap gap-2 mt-2">
                      <a className="btn btn-outline-light btn-sm" href={profile.social_links[item.key] || item.href} target="_blank" rel="noreferrer">
                        Open {item.label}
                      </a>
                    </div>
                  </div>
                ))}
              </div>

              <div className="d-flex flex-wrap gap-2 mt-4">
                <button className="btn btn-primary" onClick={saveProfile} disabled={savingProfile}>
                  {savingProfile ? 'Saving...' : 'Save Profile'}
                </button>
                <button className="btn btn-outline-light" onClick={fetchProfile}>
                  Refresh Profile
                </button>
              </div>
            </>
          ) : (
            <p className="text-muted">Register or login to view and edit your profile, photo, and social links.</p>
          )}
        </div>
      </section>
    </div>
  );
}

export default Auth;
