                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {result && (
        <div className="row">
          <div className="col-12">
            <div className="card bg-dark text-white">
              <div className="card-body">
                <h4 className="card-title">Scan Result</h4>
                <div className="row">
                  <div className="col-md-6">
                    <p className="mb-1">
                      <strong>Status:</strong>{' '}
                      <span
                        className={
                          result.status === 'MALICIOUS'
                            ? 'text-danger'
                            : result.status === 'SUSPICIOUS'
                            ? 'text-warning'
                            : 'text-success'
                        }
                      >
                        {result.status}
                      </span>
                    </p>
                    <p className="mb-1">
                      <strong>File:</strong> {result.file_name}
                    </p>
                    <p className="mb-1">
                      <strong>Type:</strong> {result.file_type || 'Unknown'}
                    </p>
                    <p className="mb-1">
                      <strong>Size:</strong> {result.file_size} bytes
                    </p>
                    <p className="mb-1">
                      <strong>Entropy:</strong> {result.entropy}
                    </p>
                  </div>
                  <div className="col-md-6">
                    <p className="mb-1">
                      <strong>SHA256:</strong> <code className="text-break">{result.sha256}</code>
                    </p>
                    <p className="mb-1">
                      <strong>MD5:</strong> <code>{result.md5}</code>
                    </p>
                    <p className="mb-1">
                      <strong>SHA1:</strong> <code>{result.sha1}</code>
                    </p>
                  </div>
                </div>

                {result.indicators && result.indicators.length > 0 && (
                  <div className="mt-3">
                    <h6>Suspicious Indicators</h6>
                    <ul>
                      {result.indicators.map((indicator, idx) => (
                        <li key={idx}>{indicator}</li>
                      ))}
                    </ul>
                  </div>
                )}

                {result.scan_id && (
                  <div className="mt-3">
                    <a
                      href={`/api/malware/report/${result.scan_id}?download=1`}
                      className="btn btn-outline-light btn-sm"
                    >
                      Download Full Report
                    </a>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

